import { useContext, useEffect, useRef, useState } from "react"
import styles from './DashboardLevel4.module.css'
import { BASE_URL } from "../../constants"
import { format, formatDate } from "date-fns"
import AppContext from "../../context"
import filterUtils from "../../utils/filter-utils"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaAngleDoubleLeft, FaAngleDoubleRight, FaAngleLeft, FaAngleRight, FaChartLine, FaSortDown, FaSortUp, FaTable } from "react-icons/fa"
import { useParams } from "react-router-dom"
import TableObserved from "../../components/Observer/observer"
import { GrLineChart } from "react-icons/gr"
import { TbTable } from "react-icons/tb"

// ========================================= CHART IMPORT =========================================  //
import {
    Chart as ChartJS,
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend,
    ChartData,
    ChartOptions,
    defaults
} from 'chart.js'

import { Plugin } from 'chart.js'
import { Line } from 'react-chartjs-2'
import { DashboardFollowingLevel4 } from "../../entities/FollowingErrorEntity"
import { DashboardFollErrService } from "../../services/following_error"
import ExcelUtils from "../../utils/excel"

ChartJS.register(
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend
)

defaults.maintainAspectRatio = false
defaults.responsive = true
// ========================================= CHART IMPORT =========================================  //


interface FollowingErrorPageProps {
    realtime: boolean
    setRealtime: (value: boolean) => void
    refresh: number
    start_date: Date
    end_date: Date
    setHandleGenerateExcel: (fn: (() => void) | null) => void
}


const FollowingErrorPage: React.FC<FollowingErrorPageProps> = ({ realtime, setRealtime, refresh, start_date, end_date, setHandleGenerateExcel }) => {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    const { machineId } = useParams()

    const CHART_COLORS = {
        chartLine: '#fb8500',
        graphicGood: 'rgba(41, 191, 18, 0.21)',
        graphicWarn: 'rgba(244, 188, 20, 0.28)',
        graphicAlarm: 'rgba(213, 14, 81, 0.2)',
    }

    const [activeHourIndex, setActiveHourIndex] = useState(new Date())
    const [isAuto, setIsAuto] = useState(true)
    const [viewMode, setViewMode] = useState<'chart' | 'table' | 'table-ool'>('chart')
    const [sortedCols, setSortedCols] = useState<keyof DashboardFollowingLevel4 | null>(null)
    const [sortedColsType, setSortedColsType] = useState<"ascending" | "descending">("ascending")


    // ========================================= STATE FOLLOWING ERROR BY DATE =========================================  //
    const [tableData, setTableData] = useState<DashboardFollowingLevel4[]>([])
    const [tableDataCache, setTableDataCache] = useState<DashboardFollowingLevel4[]>([])
    const mappedDataRef = useRef<{ [key: string]: DashboardFollowingLevel4[] }>({})

    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})

    const [chartData, setChartData] = useState<ChartData<'line'>>({ labels: [], datasets: [] })
    const [chartOptions, setChartOptions] = useState<ChartOptions<'line'>>({})

    const firstData = useRef<DashboardFollowingLevel4 | null>(null)
    // ========================================= STATE FOLLOWING ERROR BY DATE =========================================  //


    // ========================================= STATE FOLLOWING ERROR REALTIME =========================================  //
    let followingErrorSocket: WebSocket | null = null
    let reconnectFollowingError = true

    const [tableDataRealtime, setTableDataRealtime] = useState<DashboardFollowingLevel4[]>([])
    const [tableDataRealtimeCache, setTableDataRealtimeCache] = useState<DashboardFollowingLevel4[]>([])

    const [tableDataRealtimeFilter, setTableDataRealtimeFilter] = useState<{ [key: string]: string }>({})

    const [chartDataRealtime, setChartDataRealtime] = useState<ChartData<'line'>>({ labels: [], datasets: [], })
    const [chartOptionsRealtime, setChartOptionsRealtime] = useState<ChartOptions<'line'>>({})

    const firstDataRealtime = useRef<DashboardFollowingLevel4 | null>(null)
    // ========================================= STATE FOLLOWING ERROR REALTIME =========================================  //


    function splitDataBy10Minutes(data: DashboardFollowingLevel4[]) {
        const map: { [key: string]: DashboardFollowingLevel4[] } = {}

        data.toReversed().forEach(item => {
            const date = new Date(item.created_at)
            const rounded = new Date(date)
            rounded.setMinutes(Math.floor(date.getMinutes() / 10) * 10)
            rounded.setSeconds(0)
            rounded.setMilliseconds(0)

            const key = format(rounded, "yyyy-MM-dd HH:mm")

            if (map[key] == undefined) {
                map[key] = []
            } else {
                map[key].push(item)
            }
        })

        return map
    }


    // ========================================= FUNCTIONS FOLLOWING ERROR BY DATE =========================================  //
    const statusArea: Plugin<'line'> = {
        id: 'statusArea',
        beforeDatasetsDraw(chart) {
            const followingErrorData = firstData.current

            const { ctx, chartArea, scales } = chart
            if (
                !chartArea ||
                !scales.x ||
                !scales.y ||
                followingErrorData?.following_error_warn == null ||
                followingErrorData?.following_error_alarm == null
            ) return

            ctx.save()

            // --- Area Normal (Green) ---
            const startNormalArea = scales.y.min
            const endNormalArea = followingErrorData?.following_error_warn ?? 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area Warn (Kuning) ---
            const startMinWarn = followingErrorData ? followingErrorData.following_error_warn : 0
            const endMinWarn = followingErrorData ? followingErrorData.following_error_alarm : 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )


            // --- Area Alarm (Merah) ---
            const startMinAlarm = followingErrorData ? followingErrorData.following_error_alarm : 0
            const endMinAlarm = scales.y.max

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            ctx.restore()
        }
    }
    const updateChart = (mapData: { [key: string]: DashboardFollowingLevel4[] }, activeHourIndex: Date) => {
        // Get Data by activeHourIndex
        const flooredMinutes = `${Math.floor(activeHourIndex.getMinutes() / 10)}0`
        const key = format(activeHourIndex, "yyyy-MM-dd HH:" + `${flooredMinutes}`)

        const groupData = mapData[key] ?? []

        if (!groupData) {
            return
        }

        // Get Labels & Data
        const newLabels = groupData.map(msg => format(msg.created_at, "HH:mm:ss"))
        const newData = groupData.map(msg => msg.following_error)

        // Get Area Warn, Alarm & Good
        const reversedData = groupData.toReversed()
        firstData.current = reversedData[0]

        // Calculate min & max y
        const dataMin = Math.min(...newData)
        const dataMax = Math.max(...newData)
        const range = dataMax - dataMin || 1
        const padding = 0.2

        const customMin = dataMin - range * padding
        const customMax = dataMax + range * padding

        setChartData({
            labels: newLabels,
            datasets: [
                {
                    label: "Following Error",
                    data: newData,
                    borderColor: CHART_COLORS.chartLine,
                    pointBackgroundColor: CHART_COLORS.chartLine,
                    pointBorderColor: '#ffffff',
                    pointHoverBackgroundColor: '#ffffff',
                    pointHoverBorderColor: CHART_COLORS.chartLine,

                    borderWidth: 4,
                    pointRadius: 0,
                },
            ],
        })

        setChartOptions({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            },
        })
    }

    const handleFilterAndSort = () => {
        const table_filtered = tableDataCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableData(table_filtered)
    }
    const filterTable = (column: keyof DashboardFollowingLevel4, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTable = (column: keyof DashboardFollowingLevel4, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const generateData = async (withLoading: boolean) => {
        if (withLoading) {
            contextShowLoadingFunc(true)
        }

        try {
            const resp = await DashboardFollErrService.DashboardLevel4(
                formatDate(start_date, 'yyyy-MM-dd'),
                formatDate(end_date, 'yyyy-MM-dd'),
                Number(machineId)
            )

            setTableData(resp)
            setTableDataCache(resp)

            const map = splitDataBy10Minutes(resp)
            mappedDataRef.current = map

            const keys = Object.keys(map)
            if (keys.length > 0) {
                const newDate = new Date(keys[keys.length - 1])
                setActiveHourIndex(newDate)
                updateChart(mappedDataRef.current, newDate)
            } else {
                updateChart(mappedDataRef.current, activeHourIndex)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }
    const followingErrorDataRows = (index: number, row: DashboardFollowingLevel4) => {
        let valueColor = 'black'
        let valueWeight = '400'

        const { following_error, following_error_warn, following_error_alarm } = row

        if (following_error_warn != undefined && following_error < following_error_warn) {
            valueColor = 'green'
            valueWeight = 'bold'
        }

        if (following_error_warn != undefined && following_error >= following_error_warn) {
            valueColor = 'orange'
            valueWeight = 'bold'
        }

        if (following_error_alarm != undefined && following_error >= following_error_alarm) {
            valueColor = 'red'
            valueWeight = 'bold'
        }

        return <>
            <td>{index + 1}</td>
            <td>{format(row.created_at, `yyyy-MM-dd HH:mm:ss`)}</td>
            <td style={{ color: valueColor, fontWeight: valueWeight }}>{row.following_error}</td>
            <td>{row.following_error_warn}</td>
            <td>{row.following_error_alarm}</td>
        </>
    }

    useEffect(() => {
        handleFilterAndSort()
    }, [tableDataFilter, sortedCols, sortedColsType])
    useEffect(() => {
        // no loading on first open
        generateData(refresh != 0)
    }, [refresh])
    // ========================================= FUNCTIONS FOLLOWING ERROR BY DATE =========================================  //


    // ========================================= FUNCTIONS FOLLOWING ERROR REALTIME =========================================  //
    const statusAreaRealtime: Plugin<'line'> = {
        id: 'statusAreaRealtime',
        beforeDatasetsDraw(chart) {
            const followingErrorData = firstDataRealtime.current

            const { ctx, chartArea, scales } = chart
            if (
                !chartArea ||
                !scales.x ||
                !scales.y ||
                followingErrorData?.following_error_warn == null ||
                followingErrorData?.following_error_alarm == null
            ) return

            ctx.save()

            // --- Area Normal (Green) ---
            const startNormalArea = scales.y.min
            const endNormalArea = followingErrorData?.following_error_warn ?? 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area Warn (Kuning) ---
            const startMinWarn = followingErrorData ? followingErrorData.following_error_warn : 0
            const endMinWarn = followingErrorData ? followingErrorData.following_error_alarm : 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )

            // --- Area Alarm (Merah) ---
            const startMinAlarm = followingErrorData ? followingErrorData.following_error_alarm : 0
            const endMinAlarm = scales.y.max

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            ctx.restore()
        }
    }
    const updateChartRealtime = (mapData: { [key: string]: DashboardFollowingLevel4[] }, activeHourIndex: Date) => {
        // Get Data by activeHourIndex
        const flooredMinutes = `${Math.floor(activeHourIndex.getMinutes() / 10)}0`
        const key = format(activeHourIndex, "yyyy-MM-dd HH:" + `${flooredMinutes}`)

        const groupData = mapData[key] ?? []

        if (!groupData) {
            return
        }

        // Get Labels & Data
        const newLabels = groupData.map(msg => format(msg.created_at, "HH:mm:ss"))
        const newData = groupData.map(msg => msg.following_error)

        // Get Area Warn, Alarm & Good
        const firstData = groupData[0]
        firstDataRealtime.current = firstData

        // Calculate min & max y
        const dataMin = Math.min(...newData)
        const dataMax = Math.max(...newData)
        const range = dataMax - dataMin || 1
        const padding = 0.2

        const customMin = dataMin - range * padding
        const customMax = dataMax + range * padding


        setChartDataRealtime({
            labels: newLabels,
            datasets: [
                {
                    label: "Following Error",
                    data: newData,
                    borderColor: CHART_COLORS.chartLine,
                    pointBackgroundColor: CHART_COLORS.chartLine,
                    pointBorderColor: '#ffffff',
                    pointHoverBackgroundColor: '#ffffff',
                    pointHoverBorderColor: CHART_COLORS.chartLine,

                    borderWidth: 4,
                    pointRadius: 0
                },
            ],
        })

        setChartOptionsRealtime({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            },
        })
    }

    const handleFilterAndSortRealtime = () => {
        const table_filtered = tableDataRealtimeCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataRealtimeFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableDataRealtime(table_filtered)
    }
    const filterTableRealtime = (column: keyof DashboardFollowingLevel4, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataRealtimeFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataRealtimeFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTableRealtime = (column: keyof DashboardFollowingLevel4, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const generateDataRealtime = async () => {
        try {
            const resp = await DashboardFollErrService.DashboardLevel4Realtime(Number(machineId))

            setTableDataRealtime(resp)
            setTableDataRealtimeCache(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    useEffect(() => {
        if (realtime) {
            generateDataRealtime()
            const interval = setInterval(generateDataRealtime, 1000)
            return () => {
                clearInterval(interval)
            }
        }
    }, [contextAccessToken, realtime])
    useEffect(() => {
        handleFilterAndSortRealtime()
    }, [tableDataRealtimeFilter, sortedCols, sortedColsType])
    // ========================================= FUNCTIONS FOLLOWING ERROR REALTIME =========================================  //

    // Auto mode
    useEffect(() => {
        if (!realtime) return
        if (!isAuto) return

        const map = splitDataBy10Minutes(tableDataRealtime)
        const newDate = new Date()
        newDate.setMinutes(Math.floor(newDate.getMinutes() / 10) * 10)

        setActiveHourIndex(newDate)
        updateChartRealtime(map, newDate)
    }, [isAuto, realtime, tableDataRealtime])

    // Manual mode
    useEffect(() => {
        if (!realtime) return
        if (isAuto) return

        const map = splitDataBy10Minutes(tableDataRealtime)
        updateChartRealtime(map, activeHourIndex)
    }, [isAuto, realtime, tableDataRealtime, activeHourIndex])

    const handleChangeActiveHourIndex = (amount: number, unit: 'hours' | 'minutes') => {
        setIsAuto(false)
        const newDate = new Date(activeHourIndex)
        const flooredMinutes = Math.floor(newDate.getMinutes() / 10) * 10
        if (unit === 'hours') {
            newDate.setHours(newDate.getHours() + amount, flooredMinutes, 0, 0)
        } else if (unit === 'minutes') {
            newDate.setHours(newDate.getHours(), flooredMinutes + amount, 0, 0)
        }
        setActiveHourIndex(newDate)
        if (!realtime) {
            updateChart(mappedDataRef.current, newDate)
        }
    }

    const handleToggle = () => {
        setIsAuto((prev) => !prev)
    }

    const handleSetPage = (page: "chart" | "table" | "table-ool", realtime: boolean) => {
        // set state
        setViewMode(page)
        setRealtime(realtime)

        // reset everything
        setSortedCols(null)
        setSortedColsType("ascending")
        setTableDataRealtimeFilter({})

        // update chart
        if (page == "chart") {
            if (realtime) {
                const map = splitDataBy10Minutes(tableDataRealtime)
                updateChartRealtime(map, activeHourIndex)
            } else {
                updateChart(mappedDataRef.current, activeHourIndex)
            }
        }
    }

    // excel
    const generateExcelRealtime = () => {
        if (tableDataRealtime.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "created_at", "following_error",
            "following_error_warn", "following_error_alarm"
        ]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableDataRealtime.length; i++) {
            values.push({
                created_at: format(
                    typeof tableDataRealtime[i].created_at === "string"
                        ? new Date(tableDataRealtime[i].created_at)
                        : tableDataRealtime[i].created_at,
                    "yyyy-MM-dd HH:mm:ss"
                ),
                following_error: `${tableDataRealtime[i].following_error}`,
                following_error_warn: `${tableDataRealtime[i].following_error_warn ?? ""}`,
                following_error_alarm: `${tableDataRealtime[i].following_error_alarm ?? ""}`,
            })
        }

        ExcelUtils.export(`Following Error Data Realtime`, column, values)
    }
    const generateExcel = () => {
        if (tableData.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "created_at", "following_error",
            "following_error_warn", "following_error_alarm"
        ]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableDataRealtime.length; i++) {
            values.push({
                created_at: format(
                    typeof tableDataRealtime[i].created_at === "string"
                        ? new Date(tableDataRealtime[i].created_at)
                        : tableDataRealtime[i].created_at,
                    "yyyy-MM-dd HH:mm:ss"
                ),
                following_error: `${tableDataRealtime[i].following_error}`,
                following_error_warn: `${tableDataRealtime[i].following_error_warn ?? ""}`,
                following_error_alarm: `${tableDataRealtime[i].following_error_alarm ?? ""}`,
            })
        }

        ExcelUtils.export(`Following Error Data`, column, values)
    }

    useEffect(() => {
        if (realtime) {
            setHandleGenerateExcel(() => generateExcelRealtime)
        } else {
            setHandleGenerateExcel(() => generateExcel)
        }

        return () => {
            setHandleGenerateExcel(null)
        }
    }, [realtime, tableDataRealtime, tableData])

    return <>
        <div className={styles.cardBodyHeader}>

            {viewMode === 'chart' && realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div style={{ gridColumn: '1 / span 3' }}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '12px 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartDataRealtime} options={chartOptionsRealtime} plugins={[statusAreaRealtime]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}

            {viewMode === 'table' && realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    <th>
                                        {headerTableRealtime("created_at", "Waktu")}
                                        {filterTableRealtime("created_at", "Waktu")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("following_error", "Following Error")}
                                        {filterTableRealtime("following_error", "Following Error")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("following_error_warn", "Following Error Warn")}
                                        {filterTableRealtime("following_error_warn", "Following Error Warn")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("following_error_alarm", "Following Error Alarm")}
                                        {filterTableRealtime("following_error_alarm", "Following Error Alarm")}
                                    </th>
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableDataRealtime)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableDataRealtime}
                                        rowFunction={followingErrorDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

            {viewMode === 'chart' && !realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div style={{ gridColumn: '1 / span 3' }}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '12px 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartData} options={chartOptions} plugins={[statusArea]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}

            {viewMode === 'table' && !realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    <th>
                                        {headerTable("created_at", "Waktu")}
                                        {filterTable("created_at", "Waktu")}
                                    </th>
                                    <th>
                                        {headerTable("following_error", "Following Error")}
                                        {filterTable("following_error", "Following Error")}
                                    </th>
                                    <th>
                                        {headerTable("following_error_warn", "Following Error Warn")}
                                        {filterTable("following_error_warn", "Following Error Warn")}
                                    </th>
                                    <th>
                                        {headerTable("following_error_alarm", "Following Error Alarm")}
                                        {filterTable("following_error_alarm", "Following Error Alarm")}
                                    </th>
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableData)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableData}
                                        rowFunction={followingErrorDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

        </div>

        <div className={styles.cardBodyFooter}>
            <div className={styles.footerLeft}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('chart', true) }}>
                    <GrLineChart />
                    <span className={styles.tooltipText}>Realtime Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('table', true) }}>
                    <TbTable />
                    <span className={styles.tooltipText}>Realtime Table</span>
                </button>
            </div>

            <div className={styles.footerMid}>
                {viewMode === 'chart' && realtime && (
                    <div className={styles.switchGroup}>
                        <label htmlFor="auto">Auto</label>
                        <label className={styles.switch}>
                            <input type="checkbox" id="auto" checked={isAuto} onChange={handleToggle} />
                            <span className={styles.slider}></span>
                        </label>
                    </div>
                )}
            </div>

            <div className={styles.footerRight}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('chart', false) }}>
                    <FaChartLine />
                    <span className={styles.tooltipText}>Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('table', false) }}>
                    <FaTable />
                    <span className={styles.tooltipText}>Table</span>
                </button>
            </div>
        </div>
    </>
}

export default FollowingErrorPage
